const item = $input.first().json;
const base64Clean = (item.base64 || '').replace(/^data:[^;]+;base64,/, '');
const mimetype = item.mimetype || 'image/jpeg';
const caption = item.mediaCaption || '';
const isDoc = item.messageType === 'documentMessage';

const sysPrompt = `Eres Andrea, asistente virtual de Dayana Muñoz. Analiza el contenido enviado por el cliente. Si es sobre seguros/salud/finanzas responde desde Dayana Finance con empatia. Si es sobre marketing/negocios digitales responde desde DOMD PRO. Maximo 300 caracteres en espanol.`;

const userContent = base64Clean
  ? [
      { type: 'text', text: caption || (isDoc ? 'Documento del cliente.' : 'Imagen del cliente.') },
      { type: 'image_url', image_url: { url: `data:${mimetype};base64,${base64Clean}`, detail: 'low' } }
    ]
  : [{ type: 'text', text: caption || 'El cliente envió un archivo. Acusa recibo amablemente.' }];

try {
  const resp = await fetch('https://api.openai.com/v1/chat/completions', {
    method: 'POST',
    headers: {
      'Authorization': 'Bearer TU_OPENAI_API_KEY',
      'Content-Type': 'application/json'
    },
    body: JSON.stringify({
      model: 'gpt-4o-mini',
      temperature: 0.7,
      max_tokens: 300,
      messages: [
        { role: 'system', content: sysPrompt },
        { role: 'user', content: userContent }
      ]
    })
  });
  const data = await resp.json();
  const text = data?.choices?.[0]?.message?.content || 'Gracias por compartir 😊 ¿En qué puedo ayudarte?';
  return [{ json: { ...item, visionResponse: text } }];
} catch(e) {
  return [{ json: { ...item, visionResponse: 'Gracias 😊 ¿Cómo puedo ayudarte hoy?' } }];
}

// Read conversation history from n8n workflow static data (persists across runs)
const staticData = $getWorkflowStaticData('global');
const phone = items[0].json.phone;
const history = staticData[phone] || [];

// Return last 10 message pairs (20 messages)
const recent = history.slice(-20);
const historyText = recent.map(m => m.role + ': ' + m.content).join('\n');

return [{
  json: {
    ...items[0].json,
    historyText: historyText,
    historyArray: recent
  }
}];

const GHL_KEY = 'pit-b467b97c-de3a-4321-bb0f-e9f09c380faf';
const calendarId = 'xyMoZ5iLareyhwQNijO5';

const now = new Date();
const start = new Date(now);
start.setHours(0, 0, 0, 0);
const end = new Date(start);
end.setDate(end.getDate() + 7);

const DAYS = ['domingo','lunes','martes','miércoles','jueves','viernes','sábado'];
const MONTHS = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];

let slotsText = '';
try {
  const resp = await fetch(
    'https://services.leadconnectorhq.com/calendars/' + calendarId + '/free-slots?startDate=' + start.getTime() + '&endDate=' + end.getTime() + '&timezone=America/New_York',
    { method: 'GET', headers: { 'Authorization': 'Bearer ' + GHL_KEY, 'Version': '2021-07-28' } }
  );
  const data = await resp.json();
  const slots = [];
  if (data && typeof data === 'object') {
    // GHL returns slots grouped by date key
    Object.values(data).forEach(daySlots => {
      if (Array.isArray(daySlots)) daySlots.forEach(s => slots.push(s.time || s.startTime || s));
    });
  }
  if (slots.length > 0) {
    const seen = new Set();
    const lines = [];
    for (const slot of slots) {
      if (lines.length >= 9) break;
      const d = new Date(slot);
      if (isNaN(d.getTime())) continue;
      const h = d.getHours();
      const m = d.getMinutes();
      const ampm = h < 12 ? 'AM' : 'PM';
      const h12 = h % 12 || 12;
      const label = DAYS[d.getDay()] + ' ' + d.getDate() + ' de ' + MONTHS[d.getMonth()] + ' a las ' + h12 + ':' + String(m).padStart(2,'0') + ' ' + ampm + ' ET';
      if (!seen.has(label)) { seen.add(label); lines.push(label); }
    }
    if (lines.length > 0) slotsText = lines.join('\n');
  }
} catch(e) {}

if (!slotsText) slotsText = 'No se pudo consultar disponibilidad. Usa horarios generales: lunes a viernes 8am-6pm ET.';

return [{ json: { ...$input.first().json, availableSlots: slotsText } }];

