const phone = $('Extraer datos').item.json.phone;
const pushName = $('Extraer datos').item.json.pushName || 'Cliente';
const reservarInfo = $('Extraer respuesta AI').item.json.reservarInfo || '';
const reagendarInfo = $('Extraer respuesta AI').item.json.reagendarInfo || '';
const cancelarRequested = $('Extraer respuesta AI').item.json.cancelarRequested || false;
const EVO_HOST = 'n8n-evolution-api.78s07r.easypanel.host';
const EVO_INSTANCE = 'Dayana%20Munoz';
const evoUrl = 'https://' + EVO_HOST + '/message/sendText/' + EVO_INSTANCE;
const base = { phone, pushName, evoUrl, ghlLocationId: 'IYslAlpLthyYmzorDhnP', ghlCalendarId: 'xyMoZ5iLareyhwQNijO5', royPhone: '16155467023' };

// CANCELAR
if (cancelarRequested) return [{ json: { ...base, action: 'cancelar' } }];

// Helper: parse date
const parseDateTime = (info) => {
  if (!info || !info.includes('T')) return null;
  const [datePart, timePart] = info.split('T');
  const [year, month, day] = datePart.split('-').map(Number);
  const [hour, minute] = (timePart || '09:00').split(':').map(Number);
    // Dynamic ET offset: EDT=UTC-4 (Mar 2nd Sun → Nov 1st Sun), EST=UTC-5
  const _dstStart = new Date(year, 2, 1); _dstStart.setDate(1 + (7 - _dstStart.getDay() + 0) % 7 + 7);
  const _dstEnd   = new Date(year, 10, 1); _dstEnd.setDate(1 + (7 - _dstEnd.getDay()) % 7);
  const _etOffset = (new Date(year, month-1, day) >= _dstStart && new Date(year, month-1, day) < _dstEnd) ? 4 : 5;
  const startUTC = new Date(Date.UTC(year, month-1, day, hour + _etOffset, minute));
  const endUTC = new Date(startUTC.getTime() + 3600000);
  const MONTHS = ['enero','febrero','marzo','abril','mayo','junio','julio','agosto','septiembre','octubre','noviembre','diciembre'];
  const DAYS = ['domingo','lunes','martes','miercoles','jueves','viernes','sabado'];
  const dateObj = new Date(Date.UTC(year, month-1, day));
  const ampm = hour < 12 ? 'AM' : 'PM';
  const h12 = hour%12||12;
  const dateStr = DAYS[dateObj.getUTCDay()]+' '+day+' de '+MONTHS[month-1]+' a las '+h12+':'+String(minute).padStart(2,'0')+' '+ampm+' ET';
  return { startTime: startUTC.toISOString(), endTime: endUTC.toISOString(), dateStr };
};

// REAGENDAR
if (reagendarInfo) {
  const parsed = parseDateTime(reagendarInfo);
  if (parsed) return [{ json: { ...base, action: 'reagendar', ...parsed, apptTitle: 'Cita reagendada - '+pushName } }];
}

// NUEVA CITA / LINK
if (!reservarInfo || !reservarInfo.includes('T')) {
  return [{ json: { ...base, action: 'link', ghlCalendarId: 'xyMoZ5iLareyhwQNijO5' } }];
}

const parsed = parseDateTime(reservarInfo);
if (!parsed) return [{ json: { ...base, action: 'link' } }];
return [{ json: { ...base, action: 'cita', ...parsed, apptTitle: 'Cita con '+pushName } }];

const ghlResp = $input.first().json;
const p = $('Parsear cita').item.json;
const contact = ghlResp.contacts && ghlResp.contacts[0];
const contactId = contact ? contact.id : '';

return [{ json: {
