  phone: p.phone, pushName: p.pushName, dateStr: p.dateStr,
  startTime: p.startTime, endTime: p.endTime,
  ghlLocationId: p.ghlLocationId, ghlCalendarId: p.ghlCalendarId,
  apptTitle: p.apptTitle, evoUrl: p.evoUrl, royPhone: p.royPhone
}}];

const body = $input.first().json?.body || {};
const fromMe = body?.data?.key?.fromMe === true;
const event = body?.event === 'messages.upsert';
const remoteJid = body?.data?.key?.remoteJid || '';
const isGroup = remoteJid.includes('@g.us');
const msg = (body?.data?.message?.conversation || body?.data?.message?.extendedTextMessage?.text || '').toLowerCase().trim();

// Mensaje de cliente (fromMe=false) que llegó al path FALSE de "Es mensaje valido?"
// Causa real: algunos eventos messages.upsert con campos raros fallan las condiciones
// Solución: reenviar al pipeline normal en vez de silenciar
if (!fromMe) {
  return (event && !isGroup) ? $input.all() : [];
}

if (!event || isGroup) return [];

// Ecos de confirmaciones enviadas por el propio bot — ignorar para no re-pausar
const botOwnPhrases = [
  '▶️', '⏸️', 'aquí estoy para ayudarte', 'aqui estoy para ayudarte',
  'andrea no responderá', 'andrea no respondera',
  'reanudado. andrea', 'pausado. andrea',
  'entendido, no te escribiré', 'entendido, no te escribire',
  'de vuelta! aquí', 'de vuelta! aqui'
];
if (botOwnPhrases.some(p => msg.includes(p))) return [];

// Proteccion: si el contacto fue continuado hace menos de 30s, no re-pausar
const staticData = $getWorkflowStaticData('global');
if (!staticData.justContinued) staticData.justContinued = {};
const targetPhone = remoteJid.split('@')[0];
const justContinuedAt = staticData.justContinued[targetPhone] || 0;
if (Date.now() - justContinuedAt < 30000) return [];

const commandWords = ['stop','continue','continuar','reanudar','no me escribas','no me molestes','unsubscribe','borrame','no quiero mensajes','no me contactes','no me llames','borra mi numero','no mas mensajes'];
const hasCommand = commandWords.some(w => msg.includes(w));

// Comando de control — pasar al flujo STOP/CONTINUE
if (hasCommand) return $input.all();

// Dayana respondió directamente a un cliente — pausar ese contacto
if (targetPhone) {
  if (!staticData.pausedContacts) staticData.pausedContacts = {};
  staticData.pausedContacts[targetPhone] = true;
  const GHL_KEY = 'pit-b467b97c-de3a-4321-bb0f-e9f09c380faf';
  const GHL_LOC = 'IYslAlpLthyYmzorDhnP';
  const H = { 'Authorization': 'Bearer ' + GHL_KEY, 'Version': '2021-07-28', 'Content-Type': 'application/json' };
  try {
    const sr = await fetch('https://services.leadconnectorhq.com/contacts/?locationId=' + GHL_LOC + '&query=' + encodeURIComponent('+' + targetPhone), { method: 'GET', headers: H });
    const sd = await sr.json();
    const contact = (sd.contacts || [])[0];
    if (contact?.id) {
      const newTags = [...new Set([...(contact.tags || []), 'lucy-paused'])];
      await fetch('https://services.leadconnectorhq.com/contacts/' + contact.id, { method: 'PUT', headers: H, body: JSON.stringify({ tags: newTags }) });
    }
  } catch(e) {}
}

return [];

const item = $input.first().json;
const docRequested = $('Extraer respuesta AI').item.json.docRequested;
