async function setGHLTag(ph, pause) {
  try {
    const sr = await fetch('https://services.leadconnectorhq.com/contacts/?locationId=' + GHL_LOC + '&query=' + encodeURIComponent('+' + ph), { method: 'GET', headers: H });
    const sd = await sr.json();
    const contacts = sd.contacts || [];
    let contactId = contacts[0]?.id;
    let currentTags = contacts[0]?.tags || [];
    if (!contactId) {
      await fetch('https://services.leadconnectorhq.com/contacts/', {
        method: 'POST', headers: H,
        body: JSON.stringify({ locationId: GHL_LOC, phone: '+' + ph, tags: pause ? ['lucy-paused'] : [] })
      });
    } else {
      const newTags = pause ? [...new Set([...currentTags, 'lucy-paused'])] : currentTags.filter(t => t !== 'lucy-paused');
      await fetch('https://services.leadconnectorhq.com/contacts/' + contactId, { method: 'PUT', headers: H, body: JSON.stringify({ tags: newTags }) });
    }
  } catch(e) {}
}

